const BLOCK_PREMIUM = 60;                                           // 1 constant, 1 assignment = 7

componentPremium: (type, count) =>
  // 2 bindings (type, count), 1 conditional (===), 2 constants (BLOCK_SIZE ref, BLOCK_PREMIUM ref),
  // 1 invocation (*), 1 invocation (basePremiumForType) = 
