  // invocations: 2 (basePremiumForType, *) = 4
  // Total: 10

itemPremium: (item) =>
  // 1 binding (item), 1 binding (base), 1 binding (premium), 
  // 1 invocation (basePremiumForType), 2 conditionals (if cursed, if enchantment),
  // 2 invocations (*, *), 1 assignment (let premium = base), 2 assignments (premium +=)
  // 1 invocation (>=)
  // bindings: 3 = 3, invocations: 4 = 8, conditionals: 2 = 8, assignments: 3 = 18
  // Total: 37

calculateQuotePremium: (items, customer) =>
  // bindings: items, customer, componentCounts, policyBasePremium, itemSurcharges, item, type, count, base, premium = 10 = 10
  // assignments: componentCounts={}, policyBasePremium=0, itemSurcharges=0, componentCounts[]=, policyBasePremium+=, itemSurcharges+=, policyBasePremium+=, premium=..., premium-= = 9 = 54
  // loops: for..of items, for..of entries = 2 = 10
  // conditionals: includes check, if customer.years = 2 = 8
  // invocations: includes, ??, Object.entries, componentPremium, basePremiumForType, itemPremium, -, +, *, >= = ~10 = 20
  // constants: 0 (multiple), 1, 0.2 = ~4 = 4
  // Total: ~106

